const SQL = await initSqlJs();
const db = new SQL.Database();
db.run(`
  CREATE TABLE IF NOT EXISTS movies (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    type TEXT,
    name TEXT,
    original_name TEXT,
    year INTEGER,
    country TEXT,
    genres TEXT,
    tags TEXT,
    rating REAL,
    vote_count INTEGER,
    desc TEXT,
    poster TEXT,
    seasons INTEGER,
    tmdb_id INTEGER
  )
`);

const stmt = db.prepare("INSERT INTO movies (type, name, original_name, year, country, genres, tags, rating, vote_count, desc) VALUES (?,?,?,?,?,?,?,?,?,?)");
for (const m of MOVIES) {
  stmt.run([m.type, m.name, m.original_name, m.year, m.country, m.genres, m.tags, m.rating, m.vote_count, m.desc]);
}
stmt.free();

const data = db.export();
const dbPath = path.join(dataDir, 'games.db');
if (fs.existsSync(dbPath)) {
  const existingBuf = fs.readFileSync(dbPath);
  const existingDb = new SQL.Database(existingBuf);
  existingDb.run(`CREATE TABLE IF NOT EXISTS movies (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    type TEXT, name TEXT, original_name TEXT, year INTEGER, country TEXT,
    genres TEXT, tags TEXT, rating REAL, vote_count INTEGER, desc TEXT,
    poster TEXT, seasons INTEGER, tmdb_id INTEGER
  )`);
  const existingMovies = existingDb.exec("SELECT COUNT(*) FROM movies");
  if (existingMovies[0].values[0][0] === 0) {
    const s = existingDb.prepare("INSERT INTO movies (type, name, original_name, year, country, genres, tags, rating, vote_count, desc) VALUES (?,?,?,?,?,?,?,?,?,?)");
    for (const m of MOVIES) {
      s.run([m.type, m.name, m.original_name, m.year, m.country, m.genres, m.tags, m.rating, m.vote_count, m.desc]);
    }
    s.free();
    const d = existingDb.export();
    fs.writeFileSync(dbPath, Buffer.from(d));
    console.log(`Done: ${MOVIES.length} movies added to existing games.db`);
  } else {
    console.log(`Movies table already has data (${existingMovies[0].values[0][0]} rows), skipping`);
  }
  existingDb.close();
} else {
  db.run(`CREATE TABLE IF NOT EXISTS games (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT, header_image TEXT, short_description TEXT, tags TEXT, genres TEXT, platforms TEXT, release_date TEXT, rating REAL, total_reviews INTEGER, positive_ratio INTEGER, has_chinese INTEGER DEFAULT 0, metacritic INTEGER DEFAULT 0, source TEXT DEFAULT 'seed')`);
  const d = db.export();
  fs.writeFileSync(dbPath, Buffer.from(d));
  console.log(`Done: ${MOVIES.length} movies seeded to data/games.db`);
}
db.close();
